verification.command:
set -e
for d in standard/ci_gates.md methodology/05_eval_and_trace.md methodology/07_eval_gated_promotion.md standard/mcp_policy.md standard/permission_classes.md standard/failure_modes.md standard/cross_repo_governance.md; do
  grep -Eq '^enforcement: consumer-aspirational' "$d" || { echo "missing consumer-aspirational: $d"; exit 1; }
  grep -Fq 'Consumer-aspirational' "$d" || { echo "missing banner: $d"; exit 1; }
done
for d in standard/provenance_policy.md standard/capability_profiles.md; do
  grep -Eq '^enforcement: partially-enforced' "$d" || { echo "missing partially-enforced: $d"; exit 1; }
  grep -Fq 'Partially enforced' "$d" || { echo "missing hybrid banner: $d"; exit 1; }
done
grep -Fq 'check C14' standard/provenance_policy.md
grep -Fq 'check C15' standard/capability_profiles.md
echo 'E05 PASS: 7 consumer-aspirational + 2 partially-enforced markings and banners present'

set -e
for d in standard/ci_gates.md methodology/05_eval_and_trace.md methodology/07_eval_gated_promotion.md standard/mcp_policy.md standard/permission_classes.md standard/failure_modes.md standard/cross_repo_governance.md standard/provenance_policy.md standard/capability_profiles.md; do
  awk 'c<2{print} /^---/{c++}' "$d" | grep -Eq '^version: 0.2.0' || { echo "not 0.2.0: $d"; exit 1; }
  awk 'c<2{print} /^---/{c++}' "$d" | grep -Fq '"0.2.0"' || { echo "no change_log 0.2.0: $d"; exit 1; }
done
echo 'E06 PASS: all 9 docs at 0.2.0 with a matching change_log entry'
